1	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
2	type Customer = { yearsWithMHPCO: number; previousContracts?: number };
3	type QuoteInput = { customer: Customer; items: Item[] };
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	};
11	
12	const COMPONENT_BASE = 25;
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	const PROCESSING_FEE = 5;
16	const FIRST_INSURANCE_SURCHARGE = 0.1;
17	const FOLLOW_UP_DISCOUNT = 0.15;
18	const CURSE_SURCHARGE = 0.5;
19	
20	export function quote(input: QuoteInput): { premium: number } {
21	  if (input.items.length === 0) return { premium: PROCESSING_FEE };
22	
23	  let policyBase = 0;
24	  let itemSurcharges = 0;
25	  const componentCounts: Record<string, number> = {};
26	  for (const item of input.items) {
27	    if (COMPONENT_TYPES.has(item.type)) {
28	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
29	    } else {
30	      const base = BASE_PREMIUMS[item.type];
31	      policyBase += base;
32	      if (item.cursed) {
33	        itemSurcharges += base * CURSE_SURCHARGE;
34	      }
35	    }
36	  }
37	  for (const count of Object.values(componentCounts)) {
38	    if (count === 3) {
39	      policyBase += 60;
40	    } else {
41	      policyBase += count * COMPONENT_BASE;
42	    }
43	  }
44	  let policyModifiers = 0;
45	  if (input.customer.previousContracts === 0) {
46	    policyModifiers += policyBase * FIRST_INSURANCE_SURCHARGE;
47	  } else if ((input.customer.previousContracts ?? 0) >= 1) {
48	    policyModifiers -= policyBase * FOLLOW_UP_DISCOUNT;
49	  }
50	  const total = Math.ceil(policyBase + itemSurcharges + policyModifiers + PROCESSING_FEE);
51	  return { premium: total };
52	}
53	
54	export function claim(_input: unknown): { payout: number } {
55	  return { payout: 0 };
56	}
